import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.JoinFactorCostModel.CostContext;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.QueryOptimizationScopeProvider.QueryOptimizationScope;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.StatisticsEstimate;
import org.eclipse.rdf4j.query.impl.MapBindingSet;
import org.junit.jupiter.api.Test;

/** Contract tests for the thin statistics facade; engine behavior is tested separately. */
class LmdbEvaluationStatisticsMemoizationTest {

	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI FIRST = VF.createIRI("urn:first");
	private static final IRI SECOND = VF.createIRI("urn:second");

	@Test
	void facadePreservesExactAlgebraLeafContracts() {
		LmdbEvaluationStatistics statistics = statistics();
		BindingSetAssignment values = values(1, 1, 2);

		assertEquals(0.0d, statistics.getCardinality(new EmptySet()));
		assertEquals(1.0d, statistics.getCardinality(new SingletonSet()));
		assertEquals(3.0d, statistics.getCardinality(values));
		assertFalse(statistics.supportsJoinEstimation());
	}

	@Test
	void rdfStatisticsBoundaryUsesTheCanonicalEnginePath() {
		LmdbEvaluationStatistics statistics = statistics();
		StatementPattern first = pattern("s", FIRST, "x");
		StatementPattern second = pattern("x", SECOND, "y");
		Join joined = new Join(first.clone(), second.clone());

		StatisticsEstimate firstEstimate = statistics.statementPattern(first, Set.of()).orElseThrow();
		StatisticsEstimate joinEstimate = statistics.multiPatternJoin(List.of(first, second), Set.of()).orElseThrow();

		assertEquals(statistics.getCardinality(first), firstEstimate.rows());
		assertEquals(statistics.getCardinality(joined), joinEstimate.rows());
		assertTrue(firstEstimate.bag().variables().containsKey("s"));
		assertTrue(joinEstimate.bag().variables().keySet().containsAll(Set.of("s", "x", "y")));
	}

	@Test
	void physicalCostingDoesNotRewriteSemanticRows() {
		LmdbEvaluationStatistics statistics = statistics();
		StatementPattern pattern = pattern("s", FIRST, "x");
		CostContext repeated = CostContext.of(Set.of("s"), 12.0d, 4.0d, true);

		var cost = statistics.estimateFactorCost(pattern, repeated).orElseThrow();

		assertEquals(statistics.getCardinality(pattern), cost.getOutputRows());
		assertEquals(4.0d, cost.getDoubleMetrics().get("plannedRepeatedInvocations"));
		assertTrue(cost.getWorkRows() >= cost.getOutputRows());
	}

	@Test
	void optimizationScopeOwnsAndReleasesRuntimeCaches() {
		LmdbEvaluationStatistics statistics = statistics();
		assertFalse(statistics.estimatorRuntime().hasPlannerCache());

		try (QueryOptimizationScope ignored = statistics.beginQueryOptimizationScope()) {
			assertTrue(statistics.estimatorRuntime().hasPlannerCache());
			assertEquals(statistics.estimatorRuntime().planTemplateCache(),
					statistics.estimatorRuntime().planTemplateCache());
		}

		assertFalse(statistics.estimatorRuntime().hasPlannerCache());
	}

	private static LmdbEvaluationStatistics statistics() {
		return new LmdbEvaluationStatistics(null, null, null, null, null, null);
	}

	private static StatementPattern pattern(String subject, IRI predicate, String object) {
		return new StatementPattern(new Var(subject), new Var("predicate", predicate), new Var(object));
	}

	private static BindingSetAssignment values(int... values) {
		BindingSetAssignment assignment = new BindingSetAssignment();
		List<BindingSet> rows = java.util.Arrays.stream(values).mapToObj(value -> {
			MapBindingSet bindings = new MapBindingSet();
			bindings.addBinding("x", VF.createLiteral(value));
			return (BindingSet) bindings;
		}).toList();
		assignment.setBindingSets(rows);
		return assignment;
	}
}
